INSERT INTO quotes (id, movie_id, text, character) VALUES
  (1, 11, 'They''ve shut down the main reactor.', 'Threepio'),
  (2, 11, 'Don''t call me a mindless philosopher, you overweight glob of grease!', 'Threepio'),
  (3, 11, 'There''s a battle going on!', 'Luke'),
  (4, 11, 'I''m a member of the Imperial Senate on a diplomatic mission to Alderaan...', 'Leia'),
  (5, 11, 'Well, I''m not going that way.', 'Threepio'),
  (6, 11, 'Well, things haven''t been the same since you left, Biggs.', 'Luke'),
  (7, 11, 'I know, but he''s got enough vaporators going to make the place pay off.', 'Luke'),
  (8, 11, 'What I really need is a droid that understands the binary language of moisture vaporators.', 'Owen'),
  (9, 11, 'This oil bath is going to feel so good.', 'Threepio'),
  (10, 11, 'Well, not at making them interesting, anyways.', 'Threepio'),
  (11, 11, 'He''s kind of a strange old hermit.', 'Luke'),
  (12, 11, 'Do you know what he''s talking about?', 'Luke'),
  (13, 11, 'Look, it''s only one more season.', 'Owen'),
  (14, 11, 'Luke, I''m shutting the power down for the night.', 'Owen'),
  (15, 11, 'and don''t talk to me about your mission, either.', 'Threepio'),
  (16, 11, 'there seems to be no stopping him.', 'Luke'),
  (17, 11, 'He was a navigator on a spice freighter.', 'Luke'),
  (18, 11, 'Now the Jedi are all but extinct.', 'Ben'),
  (19, 11, 'I''m getting too old for this sort of thing.', 'Ben'),
  (20, 11, 'Fear will keep the local systems in line.', 'Tarkin'),
  (21, 11, 'These tracks are side by side.', 'Ben'),
  (22, 11, 'We don''t need to see his identification.', 'Trooper'),
  (23, 11, 'Come let me buy you something...', 'Ben'),
  (24, 11, 'But we could pay you two thousand now, plus fifteen when we reach Alderaan.', 'Ben'),
  (25, 11, 'Even I get boarded sometimes.', 'Han'),
  (26, 11, 'I''ve been waiting for you, Jabba.', 'Han'),
  (27, 11, 'If you disappoint me again, I''ll put a price on your head so large you won''t be able to go near a civilized system for the rest of your short life.', 'Jabba'),
  (28, 11, 'It''ll take a few moments to get the coordinates from the navi-computer.', 'Han'),
  (29, 11, 'So it''ll be the last time.', 'Tarkin'),
  (30, 11, 'Remember, a Jedi can feel the Force flowing through him.', 'Ben'),
  (31, 11, 'I could almost see the remote.', 'Luke'),
  (32, 11, 'It''s a short range fighter.', 'Ben'),
  (33, 11, 'But they''re not going to get me without a fight!', 'Han'),
  (34, 11, 'Even if I could take off, I''d never get past the tractor beam.', 'Han'),
  (35, 11, 'They must be delivered safely or other star systems will suffer the same fate as Alderaan.', 'Ben'),
  (36, 11, 'Now all you want to do is stay.', 'Luke'),
  (37, 11, 'Everything is under control.', 'Han'),
  (38, 11, 'Looks like you managed to cut off our only escape route.', 'Leia'),
  (39, 11, 'You know, it''s not going to take them long to figure out what happened to us.', 'Han'),
  (40, 11, 'Shut down all the garbage mashers on the detention level.', 'Luke'),
  (41, 11, 'That oughta hold it for a while.', 'Luke'),
  (42, 11, 'Come on, buddy, we''re not out of this yet!', 'Han'),
  (43, 11, 'Your friend is quite a mercenary.', 'Leia'),
  (44, 11, 'It''s a small thermal exhaust port, right below the main port.', 'Dodonna'),
  (45, 11, 'You know what''s about to happen, what they''re up against.', 'Luke'),
  (46, 11, 'I told you I''d make it someday, Biggs.', 'Luke'),
  (47, 11, 'I got a little cooked, but I''m okay.', 'Luke'),
  (48, 11, 'How many guns do you think, Gold Five.', 'Gold Leader'),
  (49, 11, 'We should be able to see it by now.', 'Red Ten'),
  (50, 11, 'You worry about those fighters!', 'Luke'),
  (301, 62, 'EXT cave AND PLAINS - Utopia', 'A12'),
  (302, 62, 'Will you use number eight, please?', 'Receptionist'),
  (303, 62, 'Let''s see, we haven''t had the pleasure of a visit from you not since...', 'Miller'),
  (304, 62, 'Well, I hope in a few days, sweetheart.', 'Floyd'),
  (305, 62, 'How many days until you come home?', 'Child'),
  (306, 62, 'Here is a lovely assortment of African bush babies.', 'Vision Sales Girl'),
  (307, 62, 'How nice to see you, Hyewood.', 'Elena'),
  (308, 62, 'Yes, really, thank you very much.', 'Floyd'),
  (309, 62, 'We''ve just spent three months calibrating the new antenna at Tchalinko.', 'Elena'),
  (310, 62, 'Well, I suppose they''ve been having a bit of trouble with some of the equipment.', 'Floyd'),
  (311, 62, 'Denying the men permission to land was a direct violation of the I.A.S.', 'Smyslov'),
  (312, 62, 'This epidemic could easily spread to our base, Dr.', 'Smyslov'),
  (313, 62, 'The Aries-IB has become the standard Space-Station-to-Lunar surface vehicle.', 'Narrator'),
  (314, 62, 'I wonder what really IS going on up there?', 'Pilot'),
  (315, 62, 'Well, as soon as he wakes up, I''m going to go back and talk to him.', 'Pilot'),
  (316, 62, 'The two girls have taken wonderful care of me.', 'Floyd'),
  (317, 62, 'Well, I''ll tell you why I ask.', 'Pilot'),
  (318, 62, 'Here was age inconceivable - but not death, for the Moon had never lived until now.', 'Narrator'),
  (319, 62, 'Ladies and gentlemen, I should like to introduce Dr.', 'Halvorsen'),
  (320, 62, 'We will, of course, cooperate in any way possible, Dr.', 'Halvorsen'),
  (321, 62, 'The surface is made of something incredibly hard and we''ve been barely able to scratch it.', 'Michaels'),
  (322, 62, 'Any ideas about the colour?', 'Floyd'),
  (323, 62, 'And so this is the first sun that it''s had in four million years.', 'Floyd'),
  (324, 62, 'Dave, if you''ve a minute, I''d like your advice on something.', 'Poole'),
  (325, 62, 'Interesting that you mention it, because I''ve got the same problem.', 'Bowman'),
  (326, 62, 'I suppose the idea was specialized training.', 'Bowman'),
  (327, 62, 'if you want to, why don''t you?', 'Bowman'),
  (328, 62, 'Yes, but it''s to fantastic to think that they''d keep something from us.', 'Bowman'),
  (329, 62, 'Our transit time is 257 days.', 'Poole'),
  (330, 62, 'again we want to wish you a happy Birthday and God speed.', 'Mother'),
  (331, 62, 'unit should go so quickly.', 'Poole'),
  (332, 62, 'All airlock doors are secure.', 'Hal'),
  (333, 62, 'Yes, but it''s more likely that the tolerances on our testing gear are too low.', 'Poole'),
  (334, 62, 'There''s nothing wrong with it at the moment.', 'Poole'),
  (335, 62, 'What the hell is going on?', 'Bowman'),
  (336, 62, 'but it could also be any number of reasons.', 'Mission Control'),
  (337, 62, 'I''m not questioning your word, Dave, but it''s just not possible.', 'Hal'),
  (338, 62, 'Yes, well I understand you view on this now, Hal.', 'Bowman'),
  (339, 62, 'Well, they won''t get that for half an hour.', 'Poole'),
  (340, 62, 'Well, don''t worry about it.', 'Hal'),
  (341, 62, 'You must have tightened them too much.', 'Poole'),
  (342, 62, 'I suppose you''re pretty broken up about it?', 'Hal'),
  (343, 62, 'It''s more dangerous to be out of touch with Earth.', 'Bowman'),
  (344, 62, 'Let me have the control, please.', 'Bowman'),
  (345, 62, 'I can tell from the tone of your voice, Dave, that you''re upset.', 'Hal'),
  (346, 62, 'Listen to me very carefully, Hal.', 'Bowman'),
  (347, 62, 'Hey, Dave, what are you doing?', 'Hal'),
  (348, 62, 'My first instructor was Mr.', 'Hal'),
  (349, 62, 'He had been programmed to lie about this one subject for secur- ity reasons which we''ll explain later.', 'Simonson'),
  (350, 62, 'radiation in the radio spectrum which seems to have triggered by the Lunar sunrise.', 'Floyd'),
  (808, 103, 'No trouble with the Hack Bureau?', 'Personnel Officer'),
  (809, 103, 'Listen, son, you gonna get smart, you can leave right now.', 'Personnel Officer'),
  (810, 103, 'You can''t see it for the fog!', 'Man In Business Suit'),
  (811, 103, 'Someday a real rain will come and wash all this scum off the streets.', 'Travis'),
  (812, 103, 'some of them chocolate covered malted milk balls...', 'Concession Girl'),
  (813, 103, 'First push the man, then the issue.', 'Betsy'),
  (814, 103, 'I''ll tell you why people watch CBS.', 'Betsy'),
  (815, 103, 'All my life needed was a sense of direction, a sense of someplace to go.', 'Travis'),
  (816, 103, 'Threw on the emergency, jumped the seat and fucked her brains out - What do you think!', 'Wizard'),
  (817, 103, 'He''ll chase a buck straight into Jersey.', 'Wizard'),
  (818, 103, 'well, if there''s this many hackies inside, there must be lots of hares outside.', 'Dough-Boy'),
  (819, 103, 'He happens to be missing fingers.', 'Betsy'),
  (820, 103, 'Two of his fingers are missing.', 'Betsy'),
  (821, 103, 'The man you want to volunteer to help elect president.', 'Betsy'),
  (822, 103, 'Well, Betsy mam, I drive a taxi at night.', 'Travis'),
  (823, 103, 'I took Betsy to the Mayfair Coffee Shop on Broadway...', 'Travis'),
  (824, 103, 'I had a regular job for a while, days.', 'Travis'),
  (825, 103, 'Oh, you see lots of freaky stuff in a cab.', 'Travis'),
  (826, 103, 'He wanted to go to the DMZ.', 'Travis'),
  (827, 103, 'I got this guy who makes lasers.', 'Travis'),
  (828, 103, 'I don''t follow music too much.', 'Travis'),
  (829, 103, 'You''ll have fifteen minutes before the actual luncheon begins.', 'Tom'),
  (830, 103, 'Well, he should clean up this city here.', 'Travis'),
  (831, 103, 'I don''t follow music much.', 'Travis'),
  (832, 103, 'If you just wanted to fuck, why didn''t you just come right out and say it?', 'Betsy'),
  (833, 103, 'You said you didn''t feel so good...', 'Travis'),
  (834, 103, 'Just pull over to the curb a moment.', 'Young Passenger'),
  (835, 103, 'He''s a travelling salesman.', 'Dough-Boy'),
  (836, 103, 'The Magnum, you know, that''s only if you want to splatter it against the wall.', 'Andy'),
  (837, 103, 'How much to get a permit to carry?', 'Travis'),
  (838, 103, 'One hospital, then the next.', 'Travis'),
  (839, 103, 'Total organization is necessary.', 'Travis'),
  (840, 103, 'What is this for you, number five?', 'Travis'),
  (841, 103, 'She''s about 19, good-lookin." McCall says, "What can I tell you?', 'Wizard'),
  (842, 103, 'Don''t forget your pea shooter.', 'Charlie T'),
  (843, 103, 'You see, that must be what I am.', 'Wizard'),
  (844, 103, 'Are you a Secret Service Man?', 'Travis'),
  (845, 103, 'The time has come to put an end to the things that divide us: racism, poverty, way -- and to those persons who seek to divide us.', 'Palantine'),
  (846, 103, 'Her name is Betsy, but I can tell you no more than that.', 'Travis'),
  (847, 103, 'This ain''t Dodge City, cowboy.', 'Old Man'),
  (848, 103, 'Don''t you want to get out of here?', 'Travis'),
  (849, 103, 'That''s why they stopped me.', 'Iris'),
  (850, 103, 'Well, at least it wasn''t chicken.', 'Assistant'),
  (851, 103, 'Why do you want me to go back to my parents?', 'Iris'),
  (852, 103, 'What makes you so high and mighty?', 'Iris'),
  (853, 103, 'I never been to a commune.', 'Travis'),
  (854, 103, 'You just gonna leave ''em?', 'Travis'),
  (855, 103, 'I figure they''ll understand that and appreciate me for it.', 'Travis'),
  (856, 103, 'What''s the matter, baby, don''t you feel right?', 'Sport'),
  (857, 103, 'Hillbilly, you''d better get your wise ass outa here and quick, or you''re gonna be in trouble.', 'Sport'),
  (1808, 221, 'That was pretty what you were whistling.', 'Buzz'),
  (1809, 221, 'What makes you think he hates you, Judy?', 'Ray'),
  (1810, 221, 'And all the time yelling at me--that thing--the thing I told you he called me.', 'Judy'),
  (1811, 221, 'Some kids stomped a man on Twelfth Street, Judy.', 'Ray'),
  (1812, 221, 'Want me to imitate a stupid cop?', 'Jim'),
  (1813, 221, 'They were nursing on their mother and I did it.', 'Plato'),
  (1814, 221, 'Do you hear from him, son?', 'Gene'),
  (1815, 221, 'The kid has no friends yet and--', 'Father'),
  (1816, 221, 'Was it because we went to that party?', 'Father'),
  (1817, 221, 'Go on--don''t give me that.', 'Ray'),
  (1818, 221, 'They think I''ll make friends if we move.', 'Jim'),
  (1819, 221, 'You got me, Jim--but they do.', 'Ray'),
  (1820, 221, 'Go on--Give ''em to your friends.', 'Father'),
  (1821, 221, 'There''s nothing to be nervous about.', 'Mother'),
  (1822, 221, 'You don''t have to be unfriendly.', 'Jim'),
  (1823, 221, 'Where''s University and 10th?', 'Jim'),
  (1824, 221, 'Sagittarius and Aries--all as they have ever been.', 'Lecturer'),
  (1825, 221, 'May I have your attention?', 'Teacher'),
  (1826, 221, 'The shadows are getting long.', 'Jim'),
  (1827, 221, 'Cut off a button and you get to join the club!', 'Buzz'),
  (1828, 221, 'You been on chickie-runs before?', 'Buzz'),
  (1829, 221, 'Are you really going to meet them?', 'Plato'),
  (1830, 221, 'We were romantic then too--', 'Judy''S Father'),
  (1831, 221, 'I''d like to change the subject.', 'Judy''S Father'),
  (1832, 221, 'I wouldn''t do anything hasty.', 'Father'),
  (1833, 221, 'Now, Dad--I need an answer now!', 'Jim'),
  (1834, 221, 'They both got plenty breeze.', 'Moose'),
  (1835, 221, 'We got to get out of here!', 'Plato'),
  (1836, 221, 'I''m in terrible trouble.--You know that big high bluff near Miller- town Junction?', 'Jim'),
  (1837, 221, 'So I got in one of these cars and a boy called Buzz got in the other.', 'Jim'),
  (1838, 221, 'What''s that got to do with it?', 'Jim'),
  (1839, 221, 'That''s the main thing, isn''t it?', 'Father'),
  (1840, 221, 'Now I want to do one thing right and I''m not letting you run away.', 'Jim'),
  (1841, 221, 'He''s going to cheese, I tell you.', 'Crunch'),
  (1842, 221, 'I think his first name''s Ray--I have to see him.', 'Jim'),
  (1843, 221, 'You clear out of here ''fore I call the police!', 'Negro Woman'),
  (1844, 221, 'I tried to call you before.', 'Jim'),
  (1845, 221, 'You shouldn''t believe what I say when I''m with the kids.', 'Judy'),
  (1846, 221, 'I feel as if I''m walking under water.', 'Judy'),
  (1847, 221, 'I think they''re going to kill you.', 'Plato'),
  (1848, 221, 'And so terribly annoying when they cry.', 'Judy'),
  (1849, 221, 'Then shut your mouth before your guts run out!', 'Crunch'),
  (1850, 221, 'You remember that far back?', 'Jim'),
  (1851, 221, 'Leaving a light for Plato.', 'Judy'),
  (1852, 221, 'All the time I''ve been looking for someone to love me and now--I love somebody.', 'Judy'),
  (1853, 221, 'Like you were the hero in the China Seas.', 'Judy'),
  (1854, 221, 'I am addressing the boy in the planetarium.', 'Ray'),
  (1855, 221, 'Another boy and girl just ran into the planetarium.', 'Chief'),
  (1856, 221, 'Stand up and look at the stars.', 'Jim'),
  (1857, 221, 'Will you tell these guys to move back?', 'Jim');
INSERT INTO quotes (id, movie_id, text, character) VALUES
  (1858, 238, 'America has made my fortune.', 'Bonasera'),
  (1859, 238, 'But your daughter is still alive.', 'Don Corleone'),
  (1860, 238, '...a fine boy from Sicily, captured by the American Army, and sent to New Jersey as a prisoner of war...', 'Nazorine'),
  (1861, 238, 'Why do they bother him on a day like this?', 'Kay'),
  (1862, 238, 'I told you you wouldn''t like him.', 'Michael'),
  (1863, 238, 'They call Sollozzo the Turk.', 'Hagen'),
  (1864, 238, 'You''re not too rich, or too famous that I can''t help you?', 'Don Corleone'),
  (1865, 238, 'But never let him know the family''s business.', 'Don Corleone'),
  (1866, 238, 'You can say a word, pull a few strings, eh?', 'Genco'),
  (1867, 238, 'You smooth son of a bitch, let me lay it on the line for you, and your boss.', 'Woltz'),
  (1868, 238, 'If you think two million dollars in cash is just finance, I congratulate you Don Corleone.', 'Sollozzo'),
  (1869, 238, 'Send Johnny my congratulations.', 'Don Corleone'),
  (1870, 238, 'Michael called; he''s not leaving New Hampshire until tomorrow morning.', 'Hagen'),
  (1871, 238, 'Do you recognize my voice?', 'Voice'),
  (1872, 238, 'Do whatever they say; I''m going over to the main house.', 'Sonny'),
  (1873, 238, 'You have to talk some sense into him.', 'Sollozzo'),
  (1874, 238, 'Oh no you can''t, the old man''d be sore as hell if I let you get mixed up in this.', 'Sonny'),
  (1875, 238, 'The cops have it locked in and I got my people there visiting Pop all the time.', 'Sonny'),
  (1876, 238, 'But Tom, I want you to stay inside the Mall.', 'Sonny'),
  (1877, 238, 'Rocco, sit on the other side.', 'Paulie'),
  (1878, 238, 'I don''t need them, Sonny.', 'Michael'),
  (1879, 238, 'You just stand here one minute...', 'Michael'),
  (1880, 238, 'There are men who are coming to try to kill you.', 'Michael'),
  (1881, 238, 'The nerve of that son of a bitch!', 'Sonny'),
  (1882, 238, 'I found out about this Captain McCluskey who broke Mike''s jaw.', 'Hagen'),
  (1883, 238, 'You''re taking it personal, it''s just business and he''s taking it personal.', 'Sonny'),
  (1884, 238, 'Like they shoulda stopped Hitler at Munich, they shoulda never let him get away with that, they were just asking for big trouble...', 'Clemenza'),
  (1885, 238, 'In the restaurant, wait and talk a while, and then ask permission to go.', 'Clemenza'),
  (1886, 238, 'Can''t stand the aggravation.', 'Mccluskey'),
  (1887, 238, 'Listen Tom, I let my cab go; can I come in to call another one?', 'Kay'),
  (1888, 238, 'I want to get things going good before he gets better.', 'Sonny'),
  (1889, 238, 'Even the female Corleones are murderers.', 'Carlo'),
  (1890, 238, 'Well my friend, are you ready to do me this service?', 'Don Corleone'),
  (1891, 238, 'I consider it a service done to me personally and I am in the debt of each and every one of you.', 'Don Corleone'),
  (1892, 238, 'It''s not like whiskey or gambling or even women which most people want and is forbidden them by the pezzonovante of the Church and the Government.', 'Don Corleone'),
  (1893, 238, 'My youngest son had to flee, accused of Sollozzo''s murder, and I must now make arrangements so that he can come home with safety, cleared of all those false charges.', 'Don Corleone'),
  (1894, 238, 'You tell us about America.', 'Fabrizzio'),
  (1895, 238, 'Black and curly, like a doll.', 'Fabrizzio'),
  (1896, 238, 'Monday, Tuesday, Wednesday, Thursday, Friday...See, I learned it.', 'Appolonia'),
  (1897, 238, 'But you must make a family, you know.', 'Don Corleone'),
  (1898, 238, 'I can''t do them anymore, but you can, if you choose to.', 'Don Corleone'),
  (1899, 238, 'We figure entertainment will be the big factor in drawing gamblers.', 'Michael'),
  (1900, 238, 'Sometimes I gotta kick asses to make this place run right.', 'Moe'),
  (1901, 238, 'They live with us on the Mall now, but you never get close to them.', 'Kay'),
  (1902, 238, 'Then in a six month time we''re on our own; is that it?', 'Clemenza'),
  (1903, 238, 'I told you that it wouldn''t escape his eye.', 'Don Corleone'),
  (1904, 238, 'I think you have done the same with this man.', 'Don Corleone'),
  (1905, 238, 'I guess you''ve figured it all out?', 'Michael'),
  (1906, 238, 'We''re on our way to Brooklyn.', 'Tessio'),
  (1907, 238, 'I''ll send Connie an allowance, that''s all.', 'Michael'),
  (1908, 240, 'They''ve killed young Paolo!', 'Woman'),
  (1909, 240, 'The place is transformed.', 'Mr. Barrett'),
  (1910, 240, 'Gotta check up on my boys.', 'Pentangeli'),
  (1911, 240, 'My major is Fine Arts, sir.', 'Gardner'),
  (1912, 240, 'At any rate, he expects to be introduced around to some of the influential people here today, and generally treated as an ordinary guest.', 'Hagen'),
  (1913, 240, 'See what you can do, but I''d like to keep them away from the guests.', 'Michael'),
  (1914, 240, 'Pat Geary of the state of Nevada!', 'Maestro'),
  (1915, 240, '...that you''re planning to move in on the Tropicana.', 'Senator Geary'),
  (1916, 240, 'His name is "Five-Angels.', 'Anthony'),
  (1917, 240, 'Let him go back to New York; I''ve already made my plans.', 'Michael'),
  (1918, 240, 'Because you protested, it will cost a hundred more.', 'Fanucci'),
  (1919, 240, 'No...please understand...I cannot accept.', 'Vito'),
  (1920, 240, 'You and your friends have to show me a little respect, ah?', 'Fanucci'),
  (1921, 240, 'Then they would owe him a favor; that''s how he operates.', 'Clemenza'),
  (1922, 240, 'It''s only the way we collect that''s different.', 'Priest'),
  (1923, 240, 'You''re talking as though she has no right to be frightened when there are machine guns going off in her backyard.', 'Kay'),
  (1924, 240, 'Unless I''m very wrong...they''re already dead.', 'Michael'),
  (1925, 240, 'Within the compound will be fine.', 'Hagen'),
  (1926, 240, 'But, let me tell you, the important thing is that you''re all right.', 'Roth'),
  (1927, 240, 'We will do this historical thing together, and even your Father could never dream it would be possible.', 'Roth'),
  (1928, 240, 'What assurances do I have that there will be no more kidnapping, no more hits?', 'Pentangeli'),
  (1929, 240, 'Frankie...do you respect me?', 'Michael'),
  (1930, 240, 'I went over and bought a paper...', 'Courier'),
  (1931, 240, 'We think it makes Vegas look like the corner crap game.', 'Sam Roth'),
  (1932, 240, 'A hundred million dollars.', 'Roth'),
  (1933, 240, 'Michael, people here look at me as a reliable man.', 'Roth'),
  (1934, 240, 'or rather some possible justification for what he possibly did.', 'Hagen'),
  (1935, 240, 'Frankie Pentangeli murder attempt.', 'Sergeant'),
  (1936, 240, 'Honey, go down to the casino?', 'Roth'),
  (1937, 240, 'This was a great man; a man with vision and guts; and there isn''t even a plaque or a signpost or a statue of him in that town.', 'Roth'),
  (1938, 240, 'There are maybe a few hundred die-hards in the Sierra Muestra; but government troops are going to clean them out any day.', 'Corngold'),
  (1939, 240, 'Ole Johnny knows all the places.', 'Fredo'),
  (1940, 240, 'What do you want me to do?', 'Fredo'),
  (1941, 240, 'If ever I can do something for you, in return, please come to me.', 'Vito'),
  (1942, 240, 'See me again in another six months.', 'Vito'),
  (1943, 240, 'Of course, Signora Colombo can stay in the flat.', 'Roberto'),
  (1944, 240, 'No, Senator, I never talked to him.', 'Cicci'),
  (1945, 240, 'There are still things I have to do.', 'Michael'),
  (1946, 240, 'I''m sure we all agree with our esteemed colleague.', 'Senator Kane'),
  (1947, 240, 'My personal protest can only be made to the people of this country.', 'Michael'),
  (1948, 240, 'He says he doesn''t know anything, and I believe him.', 'Hagen'),
  (1949, 240, 'You''re nothing to me now, Fredo; not a brother, not a friend, I don''t want to know you, or what happens to you.', 'Michael'),
  (1950, 240, 'He came, at his own expense, to aid his brother in his trouble.', 'Hagen'),
  (1951, 240, 'Years ago Frankie had a young girlfriend; he called her his co-wife.', 'Michael'),
  (1952, 240, 'You held me a prisoner once; will you try again?', 'Kay'),
  (1953, 240, 'I think I did things to myself, to hurt myself, so that you would know -- and you would be hurt too.', 'Connie'),
  (1954, 240, 'Are you sure of what we''re doing; what we''ll gain; what does the family gain?', 'Hagen'),
  (1955, 240, 'You were around the old timers who dreamed up how the Families should be organized, how they based it on the old Roman Legions, and called them ''Regimes''...', 'Hagen'),
  (1956, 240, 'I''m an old man; at my age, it''s too late to start worrying.', 'Roth'),
  (1957, 240, 'my brother Fredo, here''s my Mom.', 'Sonny'),
  (2058, 247, 'Avec cette pluie ca risque de prendre un moment.', 'Cab Driver'),
  (2059, 247, 'Speaks the language of love.', 'Cab Driver'),
  (2060, 247, 'Je ne suis jamais venue dans cet hotel.', 'Zoey'),
  (2061, 247, 'Because you''re...a good person.', 'Zoey'),
  (2062, 247, 'That''s something more important than the orgasm.', 'Zoey'),
  (2063, 247, 'It''s my choice to sleep with you.', 'Zoey'),
  (2064, 247, 'Void of feeling, emotion...void of destiny.', 'Zoey'),
  (2065, 247, 'I''m sorry for calling you a prostitute.', 'Zed'),
  (2066, 247, 'I thought you were going to call.', 'Eric'),
  (2067, 247, '[Get the fuck out of here you fucking whore!]', 'Eric'),
  (2068, 247, 'Why don''t you find a nice girl in the suburbs?', 'Eric'),
  (2069, 247, 'Well, to be honest there really wasn''t much happening for me in the states.', 'Zed'),
  (2070, 247, 'And lately we have just been bombing fascists here in Paris.', 'Eric'),
  (2071, 247, 'He just wants to claim you.', 'Claude'),
  (2072, 247, 'And for being greedy capitalists perhaps they will remain closed next Bastille day.', 'Eric'),
  (2073, 247, 'We''d have to be totally incompetent not to stop him.', 'Eric'),
  (2074, 247, 'I don''t know...it connects the two vaults.', 'Eric'),
  (2075, 247, 'From the inside I could open the Caliber vault in five minutes.', 'Zed'),
  (2076, 247, 'You have to look at the Starship Enterprise as a metaphor for the human brain.', 'Oliver'),
  (2077, 247, '[Don''t want to get air bubbles in my veins.]', 'Eric'),
  (2078, 247, 'Yes, tomorrow we pull the biggest job in French history.', 'Eric'),
  (2079, 247, 'Yeah, and his dad''s French.', 'Oliver'),
  (2080, 247, 'It''s really good, you know?', 'Oliver'),
  (2081, 247, 'And chain the gate to the sub lobby shut.]', 'Eric'),
  (2082, 247, '[You think we''re fucking amateurs?', 'Eric'),
  (2083, 247, 'It''s only things in there.', 'Eric'),
  (2084, 247, 'Don''t you ever conflict with me during work again!', 'Eric'),
  (2085, 247, 'Why don''t you open the vault?', 'Eric'),
  (2086, 247, 'I knew I should have been the one to kill him.', 'Jean'),
  (2087, 247, 'Where''ve you been," said the greasy fellow behind the desk, "fifty francs won''t get you a close look these days."]', 'Ricardo'),
  (2088, 247, '["Ya know," says the whore, "that''s what the last guy said."]', 'Ricardo'),
  (2089, 247, '[I have had enough of this nonsense!', 'Eric'),
  (2090, 247, 'So if there aren''t any more fucking stupid questions I''ll go downstairs and see if we''re in yet.', 'Eric'),
  (2091, 247, 'In the mean time, have a nice day.]', 'Eric'),
  (2092, 247, '[If the police decide to come in...kill them.', 'Eric'),
  (2093, 247, 'Oh, I wouldn''t want to do that.', 'Eric'),
  (2094, 247, 'Why don''t you throw out your gun?]', 'Eric'),
  (2095, 247, 'They''re just blasting the vault open.]', 'Jean'),
  (2096, 247, 'I''ll be at the other vault waiting for you to call to me.', 'Oliver'),
  (2097, 247, 'And you''ll never leave this place alive!]', 'Woman Customer'),
  (2098, 247, 'And killing all these assholes-- ] [--isn''t going to do us a damn bit of good now, is it?]', 'Eric'),
  (2099, 247, '[The moment of truth my love.', 'Eric'),
  (2100, 247, 'Not in the movies, not in real life.', 'Eric'),
  (2101, 247, 'They say they don''t make deals with terrorists.', 'Eric'),
  (2102, 247, 'So they know that you''re a--]', 'Eric'),
  (2103, 247, 'Do we have a covering of some kind?', 'Zed'),
  (2104, 247, 'Do you really love your bitch whore girlfriend that much?', 'Eric'),
  (2105, 247, 'Never let a girl come between two men.', 'Eric'),
  (2106, 247, 'We''re going to lock ourselves into one of the air tight vaults...if any of them are still open.', 'Zoe'),
  (2107, 247, 'Come Zed...I''m going to cut you like a sausage.', 'Eric'),
  (2508, 284, 'On November first, 1959, the population of New York City was 8,042,783.', 'Bud'),
  (2509, 284, 'It''s a real nice apartment - nothing fancy -- but kind of cozy -- just right for a bachelor.', 'Bud'),
  (2510, 284, 'I told you -- with my mother.', 'Sylvia'),
  (2511, 284, 'Eichelberger -- in the Mortgage Loan Department -- last night he had a little Halloween party here --', 'Bud'),
  (2512, 284, 'I''m in this bar on Sixty-first Street -- and I got to thinking about you -- and I figured I''d give you a little buzz.', 'Dobisch'),
  (2513, 284, 'I mean - barging in on your mother -- in the middle of the night?', 'Blonde'),
  (2514, 284, 'She''s the best operator in the building.', 'Bud'),
  (2515, 284, 'I wouldn''t be surprised if you heard from him before the day is over.', 'Dobisch'),
  (2516, 284, 'No, I''m all tied up on Thursday -- let''s schedule that meeting for Friday.', 'Eighelberger'),
  (2517, 284, 'You may not realize it, Miss Kubelik, but I''m in the top ten -- efficiency-wise and this may be the day -- promotion-wise.', 'Bud'),
  (2518, 284, 'Eichelberger, in Mortgage and Loan -- they''d both like to have you transferred to their departments.', 'Sheldrake'),
  (2519, 284, 'Four rotten apples in a barrel -- no matter how large the barrel -- you realize that if this ever leaked out --', 'Sheldrake'),
  (2520, 284, 'You can have both tickets.', 'Sheldrake'),
  (2521, 284, 'I''ve been waiting for you.', 'Bud'),
  (2522, 284, 'They got a great little band at El Chico, in the Village -- it''s practically around the corner from where you live.', 'Bud'),
  (2523, 284, 'Look, Jeff -- we had two wonderful months this summer -- and that was it.', 'Fran'),
  (2524, 284, 'Bring us two more drinks.', 'Sheldrake'),
  (2525, 284, 'Not back to that leaky boat --', 'Fran'),
  (2526, 284, 'We just dropped in to wish him the best.', 'Dobisch'),
  (2527, 284, 'That''s the life, all right.', 'Bud'),
  (2528, 284, 'They seem friendly enough.', 'Fran'),
  (2529, 284, 'Maybe if I wore it a little more to the side -- is that better?', 'Bud'),
  (2530, 284, 'Where you going, Buddy-boy?', 'Kirkeby'),
  (2531, 284, 'I said I had no family -- I didn''t say I had an empty apartment.', 'Bud'),
  (2532, 284, 'Because he''s unhappy at home -- because he''s lonely, that''s why -- all that was before you, Fran -- I''ve stopped running.', 'Sheldrake'),
  (2533, 284, 'Don''t you know what night this is?', 'Bartender'),
  (2534, 284, 'I broke a nail trying to get the ice-tray out.', 'Margie'),
  (2535, 284, 'Roll up her right sleeve.', 'Dr. Dreyfuss'),
  (2536, 284, 'I told you we had a fight -- that''s what it was about -- Miss Olsen -- you know that other girl you saw --', 'Bud'),
  (2537, 284, 'Why don''t you grow up, Baxter?', 'Dr. Dreyfuss'),
  (2538, 284, 'Come on -- help me round up some flies.', 'Tommy'),
  (2539, 284, 'What kind of talk is that?', 'Bud'),
  (2540, 284, 'Who are you calling, Miss Kubelik?', 'Bud'),
  (2541, 284, 'Nu, little lady, how are we feeling today?', 'Mrs. Dreyfuss'),
  (2542, 284, 'You wash ''em, you break ''em.', 'Mrs. Dreyfuss'),
  (2543, 284, 'Yeah -- I know what you mean.', 'Bud'),
  (2544, 284, 'As one woman to another -- I''m sure she''ll understand --', 'Fran'),
  (2545, 284, 'What''s holding things up?', 'Sylvia'),
  (2546, 284, 'Miss Olsen, will you come into my office, please?', 'Sheldrake'),
  (2547, 284, 'I have to run down to the grocery anyway -- all that''s left around here is one frozen pizza -- I''ll be right back -- okay?', 'Bud'),
  (2548, 284, 'Oh, I remember -- I was cooking myself an Italian dinner.', 'Bud'),
  (2549, 284, 'Worse than that -- she was the wife of my best friend -- and I was mad for her.', 'Bud'),
  (2550, 284, 'Neither of them showed up for work today.', 'Kirkeby'),
  (2551, 284, 'Sometimes I have dinner with Ed Sullivan, sometimes with Dinah Shore or Perry Como -- the other night I had dinner with Mae West -- of course, she was much younger then.', 'Bud'),
  (2552, 284, 'No, no -- just had a little accident.', 'Bud'),
  (2553, 284, 'After all, you don''t really want her, and I do, and although it may sound presumptuous, she needs somebody like me.', 'Bud'),
  (2554, 284, 'But first the property settlement has to be worked out -- then it takes six weeks in Reno -- meanwhile, I''m going to enjoy being a bachelor for a while.', 'Sheldrake'),
  (2555, 284, 'Here''s the breakdown of figures on personnel turnover.', 'Bud'),
  (2556, 284, 'What''s gotten into you, Baxter?', 'Sheldrake'),
  (2557, 284, 'Sorry it took me so long on the phone.', 'Sheldrake');
INSERT INTO quotes (id, movie_id, text, character) VALUES
  (2808, 348, 'We can haul him out of there if we have to.', 'Standard'),
  (2809, 348, 'No, I can''t see far enough.', 'Standard'),
  (2810, 348, 'Hey, can you guys hear me?', 'Roby'),
  (2811, 348, 'Don''t know -- maybe we''ll be real lucky and he just broke his neck.', 'Hunter'),
  (2812, 348, 'Martin, this is an order!', 'Standard'),
  (2813, 348, 'Let''s let the machine work on him.', 'Standard'),
  (2814, 348, 'He went into the pyramid alone.', 'Standard'),
  (2815, 348, 'I think that''s how it''s getting oxygen to him.', 'Roby'),
  (2816, 348, 'We can''t pull it loose, but we can cut off everything but the bottom layer, where it''s stuck to his face.', 'Hunter'),
  (2817, 348, 'Jesus, what can we put under it?', 'Melkonis'),
  (2818, 348, 'That could have gone right through the hull -- taken weeks to patch it.', 'Standard'),
  (2819, 348, 'Look there, what''s that stain on his lungs?', 'Roby'),
  (2820, 348, 'At first I thought they were jars too, or artifacts anyway.', 'Melkonis'),
  (2821, 348, 'The rest of you continue.', 'Standard'),
  (2822, 348, 'We don''t want it escaping.', 'Standard'),
  (2823, 348, 'My God, it''s lethal even when it''s dead!', 'Roby'),
  (2824, 348, 'The important thing is just to get away from here as fast as possible.', 'Roby'),
  (2825, 348, 'If there were a native ecology, it would have to be microscopic.', 'Melkonis'),
  (2826, 348, 'This dust is getting clogged in the intakes again!', 'Faust'),
  (2827, 348, 'That''s okay, he can remain in hypersleep until they''re ready to treat him.', 'Standard'),
  (2828, 348, 'I think that''s a pretty reasonable request.', 'Standard'),
  (2829, 348, 'What''s the matter, you don''t like this stuff?', 'Melkonis'),
  (2830, 348, 'It was growing in him the whole time and he didn''t even know it!', 'Melkonis'),
  (2831, 348, 'And then we run out of food and oxygen.', 'Hunter'),
  (2832, 348, 'And what do we do when we find it?', 'Melkonis'),
  (2833, 348, 'Give it a hell of a shock.', 'Hunter'),
  (2834, 348, 'A long time by the clock, but a short time to us.', 'Standard'),
  (2835, 348, 'They''re insulated down to here -- just be careful not to touch the end.', 'Hunter'),
  (2836, 348, 'Whoever finds it first, catches it in the net and ejects it from the nearest airlock.', 'Standard'),
  (2837, 348, 'It''s coming from below us.', 'Faust'),
  (2838, 348, 'It looks completely different from the first one -- it''s more like a worm with legs...', 'Standard'),
  (2839, 348, 'Somebody gimme a hand, I''ll get the stuff.', 'Faust'),
  (2840, 348, 'We can''t pump poison gas down into the cooling unit!', 'Hunter'),
  (2841, 348, 'I hope you won''t need me, but if you do, I''m here.', 'Faust'),
  (2842, 348, 'They''re getting pretty close now.', 'Melkonis'),
  (2843, 348, 'By eating our food supplies.', 'Roby'),
  (2844, 348, 'What''s that supposed to mean?', 'Standard'),
  (2845, 348, 'I think it''s time we took a hard look at those heiroglyphs.', 'Roby'),
  (2846, 348, 'This is all the same creature.', 'Roby'),
  (2847, 348, 'It''s in the main air lock.', 'Faust'),
  (2848, 348, 'It must have been the first thing sucked out of the ship.', 'Standard'),
  (2849, 348, 'We can''t kill it on board.', 'Hunter'),
  (2850, 348, 'But the lifeboat can''t accelerate to light speed.', 'Standard'),
  (2851, 348, 'There''s only one hypersleep freezer on the lifeboat.', 'Standard'),
  (2852, 348, 'We''ve got a lot to accomplish.', 'Standard'),
  (2853, 348, 'Should we go outside and bring him in?', 'Hunter'),
  (2854, 348, 'I think somebody should stay by the lifeboat to slam the door on the thing once it''s inside, and to serve as...', 'Hunter'),
  (2855, 348, 'And you stand aside while we drive it in, then shut the hatch, launch the boat, and --', 'Standard'),
  (2856, 348, 'I''ll get you out of there.', 'Roby'),
  (2857, 348, 'Engines will overload in 3 minutes, 30 seconds!', 'Computer'),
  (3208, 475, 'What you doin'' with my mama''s car?', 'Bonnie'),
  (3209, 475, 'Guess some little old lady wasn''t so nice.', 'Bonnie'),
  (3210, 475, 'Hey, what''s your name, anyway?', 'Bonnie'),
  (3211, 475, 'You''re like me and you want different things.', 'Clyde'),
  (3212, 475, 'Where you been keeping yourself?', 'Bonnie'),
  (3213, 475, 'We just come by for a last look.', 'Farmer'),
  (3214, 475, 'Give me a loaf of bread, a dozen eggs and a quart of milk.', 'Clyde'),
  (3215, 475, 'Well, y''see, there''s this tank underground, and the gas comes up this tube into the pump and into your car, M''am.', 'C.W.'),
  (3216, 475, 'I served a year in the reform school.', 'C.W.'),
  (3217, 475, 'Ain''t gonna spread out all over the state...', 'Clyde'),
  (3218, 475, 'If you boys want to talk why don''t you go outside?', 'Bonnie'),
  (3219, 475, 'Bonnie, I want to talk to you.', 'Clyde'),
  (3220, 475, 'I ain''t no sweet young thing.', 'Clyde'),
  (3221, 475, 'I just ain''t gonna work in your Daddy''s church--That''s final.', 'Buck'),
  (3222, 475, 'I sure am pleased to meet you.', 'C.W.'),
  (3223, 475, 'Don''t take my picture now.', 'Blanche'),
  (3224, 475, 'Hey, that time you broke out of jail, she talk you into goin'' back?', 'Clyde'),
  (3225, 475, 'I did it so I could get off work detail-- breakin'' those damned rocks with a hammer day and night.', 'Clyde'),
  (3226, 475, 'He give me the grocery number.', 'Buck'),
  (3227, 475, 'Boy, you ain''t never gonna beat me but you keep tryin'' now.', 'Buck'),
  (3228, 475, 'We''re separate from everybody else, and they know it.', 'Bonnie'),
  (3229, 475, 'Now ''Sal'' was a gal of rare beauty, Though her features were coarse and tough; She never once faltered from duty To play on the ''up and up''.', 'Bonnie'),
  (3230, 475, 'Just shut up your big mouth!', 'Bonnie'),
  (3231, 475, 'Clyde...honey...I didn''t mean all that, honey.', 'Bonnie'),
  (3232, 475, 'When he saw several machine guns in the car he was certain he''d caught Clyde Barrow, Bonnie Parker, and maybe Buck Barrow and the third unidentified member of the gang.', 'Buck'),
  (3233, 475, '--Now you ain''t hardly doin'' your job, Texas Ranger.', 'Clyde'),
  (3234, 475, 'C''mon, now, Clyde, you and Bonnie first.', 'Buck'),
  (3235, 475, 'Can''t get more''n this out of a Plymouth!', 'C.W.'),
  (3236, 475, 'I ain''t gone to risk my life in Oklahoma.', 'First Policeman'),
  (3237, 475, '--she''s such a silly-Billy...', 'Bonnie'),
  (3238, 475, 'Turn around and let''s get back to town.', 'Eugene'),
  (3239, 475, 'Well, you two must be in love, I bet.', 'Bonnie'),
  (3240, 475, 'Hey, maybe y''all ought to join up with us.', 'Clyde'),
  (3241, 475, 'keep your tail up, keep yer tail up, keep yer tail up, Oh, Horsey!', 'Buck'),
  (3242, 475, 'They want us to look big so''s they''ll look big when they catch us.', 'Clyde'),
  (3243, 475, 'Well, why don''t you all go play with it somewhere else?', 'Bonnie'),
  (3244, 475, 'What mama?...she''s just an old woman now...I have no mama...', 'Bonnie'),
  (3245, 475, 'Baptist...oh, and he thought the world of Buck, my daddy did, even knowing that Buck was serving time in jail.', 'Blanche'),
  (3246, 475, 'The men are on the other side.', 'Blanche'),
  (3247, 475, 'It''s Bonnie Parker and Clyde Barrow.', 'Man'),
  (3248, 475, 'Here I am, see here, right behind Joe Boyd here.', 'Billy'),
  (3249, 475, 'How in the nama God could I leave my brother to die when he was already dead when I left him?', 'Clyde'),
  (3250, 475, 'Oh...Hey, Pa, how you like havin'' a coupla big deals stayin'' with you?', 'C.W.'),
  (3251, 475, 'Look what they do to you, and you don''t even get your name in the paper-- just pictures put on your skin, by "Bonnie and Clyde"-- --why they''re a coupla kids.', 'Malcolm'),
  (3252, 475, 'You sure don''t resemble that no more.', 'Clyde'),
  (3253, 475, 'The Poem of Bonnie and Clyde!', 'Clyde'),
  (3254, 475, '...better go then, you better go, better go...', 'Malcolm'),
  (3255, 475, 'What do you think, Clarence?', 'Malcolm'),
  (3256, 475, 'Oh no, I never gave it thought.', 'Bonnie'),
  (3257, 475, 'Sure, drive with one eye shut.', 'Clyde'),
  (3558, 539, 'Never did eat your lunch, did you.', 'Sam'),
  (3559, 539, 'Meeting you in secret so we can be...', 'Mary'),
  (3560, 539, 'We can see each other, we can even have dinner...', 'Mary'),
  (3561, 539, 'Sam, let''s go get married.', 'Mary'),
  (3562, 539, 'Teddy was furious when he found out I''d taken tranquilizers!', 'Caroline'),
  (3563, 539, 'Forty thousand, says here...', 'Cassidy'),
  (3564, 539, 'You need a week-end in Las Vegas...', 'Cassidy'),
  (3565, 539, 'Turn your motor off, please.', 'Patrolman'),
  (3566, 539, 'Spin it around the block.', 'Car Dealer'),
  (3567, 539, 'Don''t want any bad word of mouth about California Charlie.', 'Car Dealer'),
  (3568, 539, 'If no one''s answering at the house....', 'Lowery''S Voice'),
  (3569, 539, 'All right, yes, you better come over.', 'Lowery''S Voice'),
  (3570, 539, 'But it''s no good dwelling on our losses, is it.', 'Norman'),
  (3571, 539, 'Then will you do me a favor?', 'Norman'),
  (3572, 539, 'Or do I have to tell her, cause you don''t have the guts?', 'Woman''S Voice'),
  (3573, 539, 'I think only birds look well stuffed because they''re rather...', 'Norman'),
  (3574, 539, 'I think we''re all in our private traps, clamped in them, and none of us can ever climb out.', 'Norman'),
  (3575, 539, 'Anyway, it was too much of a loss for my mother...', 'Norman'),
  (3576, 539, 'I''ve suggested it myself.', 'Norman'),
  (3577, 539, 'In your store, somewhere in your town...', 'Lila'),
  (3578, 539, 'Look, if you two are in this thing together, I don''t care, it''s none of my business...', 'Lila'),
  (3579, 539, 'She was supposed to bank it, on Friday, for her boss.', 'Lila'),
  (3580, 539, 'I think she''s here, Miss Crane.', 'Arbogast'),
  (3581, 539, 'Unless she had some wild idea that it would help me...', 'Sam'),
  (3582, 539, 'Then we''ll come back here...', 'Sam'),
  (3583, 539, 'family wants to forgive her...', 'Arbogast'),
  (3584, 539, 'Now, try to remember if this girl...', 'Arbogast'),
  (3585, 539, 'so I made her some supper.', 'Norman'),
  (3586, 539, 'you wouldn''t be fooled...', 'Arbogast'),
  (3587, 539, 'Spent last Saturday night at Bates'' Motel, out here on the old highway.', 'Arbogast'),
  (3588, 539, 'You have an awfully nice habit, Sam.', 'Lila'),
  (3589, 539, 'Where could he have gone?', 'Lila'),
  (3590, 539, 'and, well, we got a call tonight, from this detective, saying he''d traced Mary...', 'Sam'),
  (3591, 539, 'She ain''t missing so much as she''s run away.', 'Sheriff'),
  (3592, 539, 'I think something''s wrong, too, Miss.', 'Sheriff'),
  (3593, 539, 'Florrie, the Sheriff wants you to connect him with the Bates Motel.', 'Mrs. Chambers'),
  (3594, 539, 'I helped Norman pick out the dress she was buried in.', 'Mrs. Chambers'),
  (3595, 539, 'This is my room and no one will drag me out of it...', 'Mother''S Voice'),
  (3596, 539, 'You didn''t find anything.', 'Sam'),
  (3597, 539, 'I won''t feel satisfied unless I got out there, Sam.', 'Lila'),
  (3598, 539, 'she always tried to be proper.', 'Lila'),
  (3599, 539, 'and he wants practically notarized receipts.', 'Sam'),
  (3600, 539, 'and he was starting to feel the same about you.', 'Lila'),
  (3601, 539, 'I think she told Arbogast something!', 'Lila'),
  (3602, 539, 'I always thought it was the people who are alone so much who do all the talking when they get the chance.', 'Sam'),
  (3603, 539, 'Where will you get the money to do that, Bates...', 'Sam'),
  (3604, 539, 'He only half-existed to begin with...', 'Simon'),
  (3605, 539, 'That pushed him over the thin line...', 'Simon'),
  (3606, 539, 'mother killed the girl." After the murder, Norman returned as if from a deep sleep...', 'Simon'),
  (3607, 539, 'These were murders of passion, not profit.', 'Simon'),
  (3858, 567, 'The temperature, outside, 84 -- Friends -- is your life worth one dollar?', 'Announcer'),
  (3859, 567, 'Must be rough on you thinking of me wearing this cast another whole week.', 'Jeff'),
  (3860, 567, 'Six weeks -- sitting in a two-room apartment with nothing to do but look out the window at the neighbors!', 'Jeff'),
  (3861, 567, 'Is one of those bikini bombshells you always watch worth a hot poker?', 'Stella'),
  (3862, 567, 'I can smell trouble right in this apartment.', 'Stella'),
  (3863, 567, 'I''m not ready for marriage.', 'Jeff'),
  (3864, 567, 'But when I do, it''ll be to someone who thinks of life as more than a new dress, a lobster dinner, and the latest scandal.', 'Jeff'),
  (3865, 567, '-- Because she only scored sixty-one on a Look Magazine marriage quiz!', 'Stella'),
  (3866, 567, 'We sell a dozen a day in this price range.', 'Lisa'),
  (3867, 567, 'Thank you for waiting Carl.', 'Lisa'),
  (3868, 567, 'Then I had to dash back and change.', 'Lisa'),
  (3869, 567, 'Let''s not talk any more nonsense, huh?', 'Jeff'),
  (3870, 567, 'Well, at least you can''t say the dinner isn''t right.', 'Lisa'),
  (3871, 567, 'Lisa, simmer down -- will you?', 'Jeff'),
  (3872, 567, 'You sleep rarely, bathe even less, and sometime the food you even look at when they were alive!', 'Jeff'),
  (3873, 567, 'I guess I''m not the girl I thought I was.', 'Lisa'),
  (3874, 567, 'And she''ll end up fat, alcoholic and miserable.', 'Stella'),
  (3875, 567, 'The shades are still drawn in their apartment.', 'Jeff'),
  (3876, 567, 'And come back three times?', 'Jeff'),
  (3877, 567, 'Jeff -- if you could only see yourself.', 'Lisa'),
  (3878, 567, 'I don''t know, and I don''t care.', 'Lisa'),
  (3879, 567, 'He''s probably in the bedroom now, entertaining his wife with the indian rope trick.', 'Jeff'),
  (3880, 567, 'As a matter of fact, I did say "murder".', 'Jeff'),
  (3881, 567, 'I''ll watch the alleyway -- in case it goes that way.', 'Jeff'),
  (3882, 567, 'That man''s still sitting around his apartment; he isn''t panicked.', 'Doyle'),
  (3883, 567, 'Keeps to himself, and none of the neighbors got close to him, or his wife.', 'Doyle'),
  (3884, 567, 'He said Thorwald told him he had just put his wife on the train for the country.', 'Doyle'),
  (3885, 567, 'Does he have a courtesy card from the police department?', 'Jeff'),
  (3886, 567, 'You know, every day for three years I asked myself that same question?', 'Jeff'),
  (3887, 567, 'I think Thorwald''s pulling out tonight.', 'Jeff'),
  (3888, 567, 'Suppose he doesn''t come back again?', 'Lisa'),
  (3889, 567, 'Do they hide it in their husband''s clothes?', 'Jeff'),
  (3890, 567, 'Don''t be too hard on him.', 'Jeff'),
  (3891, 567, 'I wish I could be creative.', 'Lisa'),
  (3892, 567, 'I''m just warming some brandy.', 'Lisa'),
  (3893, 567, 'You mean you can explain everything that went on over there -- and is still going on?', 'Jeff'),
  (3894, 567, 'That feminine intuition sells magazines -- but in real life, it''s still a fairy tale.', 'Doyle'),
  (3895, 567, '-- I''ll answer it for you -- because he had something to hide.', 'Jeff'),
  (3896, 567, 'That depends on who "they" were.', 'Jeff'),
  (3897, 567, 'Preview -- of the coming attractions.', 'Lisa'),
  (3898, 567, 'In the whole courtyard, only one person didn''t come to the window.', 'Jeff'),
  (3899, 567, 'You take a look and tell me what you see.', 'Jeff'),
  (3900, 567, 'Let''s wait until it gets dark.', 'Lisa'),
  (3901, 567, 'And she''s reading the Bible.', 'Stella'),
  (3902, 567, 'The only way anybody could get that off would be to chop my finger -- Let''s go down and find out what''s buried in the garden.', 'Stella'),
  (3903, 567, 'Shall we vote him in, Stella?', 'Lisa'),
  (3904, 567, 'Well, if he calls in, tell him to get in touch with L.', 'Jeff'),
  (3905, 567, 'In the right hand drawer.', 'Jeff'),
  (3906, 567, 'If that woman were still alive, she''d be wearing it.', 'Jeff'),
  (3907, 567, 'I''m glad I was here when he played it.', 'Miss Lonely Hearts');
INSERT INTO quotes (id, movie_id, text, character) VALUES
  (3908, 571, 'MacGruder, have you ever seen so many gulls?', 'Melanie'),
  (3909, 571, 'Well, how long do you think...?', 'Mrs. Macgruder'),
  (3910, 571, 'Is there an ornithological reason for keeping them in separate cages?', 'Mitch'),
  (3911, 571, 'What do you call your lovebird story if not a practical...', 'Melanie'),
  (3912, 571, 'I want you to do a favor for me.', 'Melanie'),
  (3913, 571, 'Right across the bay there.', 'Clerk'),
  (3914, 571, 'I wonder if you could tell me...', 'Melanie'),
  (3915, 571, 'The one who lives in the white house across the bay?', 'Melanie'),
  (3916, 571, 'No, I''m an open book, I''m afraid.', 'Annie'),
  (3917, 571, 'To bring your sister those birds.', 'Melanie'),
  (3918, 571, 'I wrote you a letter about it, in fact, but I tore it up.', 'Melanie'),
  (3919, 571, 'What time is dinner, Mother?', 'Mitch'),
  (3920, 571, 'Don''t they ever stop migrating?', 'Annie'),
  (3921, 571, 'I opened one of the sacks when I got home, and I poured it out for them, and they wouldn''t touch it.', 'Lydia'),
  (3922, 571, 'Of course, they''re mostly hoods.', 'Cathy'),
  (3923, 571, 'He comes up every weekend, you know, even though he has his own apartment in the city.', 'Cathy'),
  (3924, 571, 'well, the newspaper said she was naked.', 'Lydia'),
  (3925, 571, 'The truth is you were running around with a pretty wild crowd...', 'Mitch'),
  (3926, 571, 'But it''s not good enough now.', 'Melanie'),
  (3927, 571, 'Look, I see no reason for being coy about this.', 'Annie'),
  (3928, 571, 'Afraid of any woman who''d give Mitch the only thing Lydia can give him -- love.', 'Annie'),
  (3929, 571, 'well, you know, you probably went to one yourself.', 'Annie'),
  (3930, 571, 'I think I''ll go to sleep.', 'Melanie'),
  (3931, 571, 'What about Thursdays and Fridays?', 'Mitch'),
