  (4072, 578, 'You take some guys off or you don''t go out.', 'Brody'),
  (4073, 578, 'I swear, this town has gone crazy.', 'Brody'),
  (4074, 578, 'With minor post- mortem lacerations and abrasions.', 'Hooper'),
