  (4096, 578, 'He was born with what he does best.', 'Quint'),
  (4097, 578, 'Reverse her and turn -- he''s taking too much line!', 'Quint'),
  (4098, 578, 'It''s a marlin or a stingray.', 'Hooper'),
  (4099, 578, 'How''re we gonna handle this?', 'Brody'),
  (4100, 578, 'Now you''ve done it, you piss-ant.', 'Quint'),
  (4101, 578, 'I caught him with a good right hand right in the snot locker and laid him amongst the sweetpeas.', 'Quint'),
  (4102, 578, 'Look a'' that -- Bayonet Iwo Jima.', 'Quint'),
  (4103, 578, 'was the bomb mission had been so secret, no distress signals was sent.', 'Quint'),
