INSERT INTO quotes (id, movie_id, text, character) VALUES
  (5079, 705, 'The Sarah Siddons Award for Distinguished Achievement is perhaps unknown to you.', 'Addison''S Voice'),
  (5080, 705, 'She played a fairy and entered - quite unexpectedly - stark naked.', 'Addison''S Voice'),
  (5081, 705, 'Why should you think I wouldn''t be?', 'Eve'),
  (5082, 705, 'I guess a real tight girdle help when you''re playin'' a lunatic.', 'Birdie'),
  (5083, 705, 'And this is my good friend and companion, Miss Birdie Coonan.', 'Margo'),
  (5084, 705, 'It couldn''t possibly interest you.', 'Eve'),
  (5085, 705, 'And one night Margo Channing came to play in ''Remembrance''...', 'Eve'),
  (5086, 705, 'I hope I see you again soon-', 'Karen'),
  (5087, 705, 'I just asked a simple question.', 'Eve'),
  (5088, 705, 'I understand they''ve got the Indians pretty well in hand...', 'Bill'),
  (5089, 705, 'You bought the new girdles a size smaller.', 'Margo'),
  (5090, 705, '- in a tin can, cellophane or wrapped in a Navajo blanket, I want you home...', 'Margo'),
  (5091, 705, 'Oh, come now, as though you were an old lady...', 'Eve'),
  (5092, 705, 'you want to be Margo''s new understudy.', 'Karen'),
  (5093, 705, 'This answer satisfies me a hundred percent.', 'Max'),
  (5094, 705, 'I''m sorry, I didn''t mean to-', 'Eve'),
  (5095, 705, 'In my case it''s necessary.', 'Max'),
  (5096, 705, 'Remind me to tell you about when I looked into the heart of an artichoke.', 'Margo'),
  (5097, 705, 'This is my cue to take you in my arms and reassure you - but I''m not going to.', 'Bill'),
  (5098, 705, 'This is the most ghoulish conversation...', 'Karen'),
  (5099, 705, 'Go do yourself some good.', 'Addison'),
  (5100, 705, 'Here you are, Maxie dear.', 'Margo'),
  (5101, 705, 'When you do, let me in on it.', 'Margo'),
  (5102, 705, 'The audition was called for 2:30.', 'Addison'),
  (5103, 705, 'Do they have auditions for television?', 'Miss Caswell'),
  (5104, 705, 'Then you listened as if someone else had written you play - whom did you have in mind?', 'Margo'),
  (5105, 705, 'I''m trying terribly hard.', 'Bill'),
  (5106, 705, 'Just a feeling, I don''t know...', 'Margo'),
  (5107, 705, 'We''ve spent weekends before with nobody talking...', 'Lloyd'),
  (5108, 705, 'Peace and quit is for libraries.', 'Margo'),
  (5109, 705, 'For that, I''m truly sorry.', 'Margo'),
  (5110, 705, 'The things you drop on your way up the ladder, so you can move faster.', 'Margo'),
  (5111, 705, 'What have I got to do with it?', 'Bill'),
  (5112, 705, 'One isolated pretty good performance by an understudy.', 'Eve'),
  (5113, 705, 'Mostly relief that I managed to stagger through it at all...', 'Eve'),
  (5114, 705, 'Maybe just a little around the edges.', 'Bill'),
  (5115, 705, 'She apologized, didn''t she?', 'Lloyd'),
  (5116, 705, 'What are you going to wear?', 'Karen'),
  (5117, 705, 'but then, I''d never met Addison deWitt.', 'Eve'),
  (5118, 705, 'I wish I could believe that.', 'Eve'),
  (5119, 705, 'Oddly enough - she didn''t say a word about Margo.', 'Eve'),
  (5120, 705, 'Not just a house I''m afraid to stay in...', 'Margo'),
  (5121, 705, 'It seemed to me I had known always that it would happen - and here it was.', 'Karen''S Voice'),
  (5122, 705, 'To the Theater world - New Haven, Connecticut, is a short stretch of sidewalk between the Shubert Theater and the Taft Hotel, surrounded by what looks very much like a small city.', 'Addison''S Voice'),
  (5123, 705, 'She''s always been so fantastically devoted to Lloyd.', 'Addison'),
  (5124, 705, 'We sat and talked, Addison.', 'Eve'),
  (5125, 705, 'At anything or anyone else - but never at me.', 'Addison'),
  (5126, 705, 'I was there, I saw you and heard you through the dressing room door!', 'Addison'),
  (5127, 705, 'Hoe can I repay the many others?', 'Eve'),
  (5128, 705, 'You were just looking around...', 'Eve'),
  (5981, 828, 'Reports are coming in from all over the Empire -- from all over the world.', 'British Announcer'),
  (5982, 828, 'Good afternoon, ladies and gentlemen, this is Drew Pearson.', 'Pearson'),
  (5983, 828, 'Just a minute, ladies and gentlemen!', 'Pearson'),
  (5984, 828, 'Tell them there won''t be any statement tonight.', 'General'),
  (5985, 828, 'We''re very curious about that, too.', 'Harley'),
  (5986, 828, 'We''ve been monitoring your radio broadcasts for a good many years.', 'Klaatu'),
  (5987, 828, 'But of course the UN doesn''t represent all of the nations.', 'Harley'),
  (5988, 828, 'What''s the report, Carlson?', 'General'),
  (5989, 828, 'He says their medicine is that much more advanced.', 'Captain'),
  (5990, 828, 'Representation could be sent only if the meeting were held in Washington." Well -- there you have it.', 'Harley'),
  (5991, 828, 'Before making any decisions, I think I should get out among your people -- become familiar with the basis for these strange, unreasoning attitudes.', 'Klaatu'),
  (5992, 828, 'Well -- this is our little family.', 'Mrs. Crockett'),
  (5993, 828, 'Would he disappear into the north woods?', 'Gabriel Heater''S Voice'),
  (5994, 828, 'Why doesn''t he come out in the open?', 'Mr. Barley'),
  (5995, 828, 'I must admit I''m a little confused.', 'Klaatu'),
  (5996, 828, 'I thought today he might show me around the city.', 'Klaatu'),
  (5997, 828, 'My mother''s a real secretary.', 'Bobby'),
  (5998, 828, 'How could they make a landing?', 'Bobby'),
  (5999, 828, 'It''s a problem in celestial mechanics.', 'Klaatu'),
  (6000, 828, 'He tears off the piece of paper and hands it to Hilda.', 'Hilda'),
  (6001, 828, 'What would you like to do this afternoon?', 'Klaatu'),
  (6002, 828, 'Oh -- I suppose Professor Barnhardt''s looking far me.', 'Klaatu'),
  (6003, 828, 'Aw, gee -- we didn''t finish our story.', 'Bobby'),
  (6004, 828, 'He was having difficulty with a problem.', 'Klaatu'),
  (6005, 828, 'Would have killed him if we hadn''t come along...', 'Cop'),
  (6006, 828, 'Sorry to trouble you, Lieutenant.', 'Klaatu'),
  (6007, 828, 'My doctor''s name was Major White -- and I had a very attractive nurse called Ruth, who''s getting married next Wednesday.', 'Klaatu'),
  (6008, 828, 'If you mean that you are afraid of us--', 'Barnhardt'),
  (6009, 828, 'What exactly is the nature of your mission, Mr.', 'Barnhardt'),
  (6010, 828, 'That''s what I came to see you about.', 'Klaatu'),
  (6011, 828, 'In such, a case the planet Earth would have to be-- --eliminated.', 'Klaatu'),
  (6012, 828, 'Would day after tomorrow be all right?', 'Klaatu'),
  (6013, 828, 'I was just going up to my room.', 'Klaatu'),
  (6014, 828, 'Carpenter showed him how to do his arithmetic.', 'Bobby'),
  (6015, 828, 'Carpenter -- right after you left -- and, gee, Mom, where do you think he went?', 'Bobby'),
  (6016, 828, 'The room right opposite mine.', 'Helen'),
  (6017, 828, 'Bobby and I have had enough excitement for tonight.', 'Helen'),
  (6018, 828, 'I -- I didn''t really pay much attention-- Bobby has such an active imagination.', 'Helen'),
  (6019, 828, 'Thanks -- I''m enjoying it right here.', 'Barnhardt'),
  (6020, 828, 'What about the robot, Colonel?', 'General'),
  (6021, 828, 'I have never seen such a stone.', 'Jeweler'),
  (6022, 828, 'He''s the only other person who knows anything about--', 'Klaatu'),
  (6023, 828, '--Honest, Mary, I''m so scared I can''t sit still.', 'Secretary'),
  (6024, 828, 'Why hasn''t he got any money?', 'Tom'),
  (6025, 828, 'You realize what this''d mean for us?', 'Tom'),
  (6026, 828, 'You''re going to marry a big hero!', 'Tom'),
  (6027, 828, 'All vehicles maintain your positions -- and hold your fire.', 'Colonel'),
  (6028, 828, 'No question about it, General -- he''s dead all right...', 'Colonel'),
  (6029, 828, 'We''ll miss you very much -- Bobby and I.', 'Helen'),
  (6030, 828, 'We of the other planets have long accepted this principle.', 'Klaatu'),
  (6131, 845, 'I beg your pardon, but aren''t you Guy Haines.', 'Bruno'),
  (6132, 845, 'I suppose you''re going to Southampton -- for the doubles.', 'Bruno'),
  (6133, 845, 'I guess I''m pretty jumpy.', 'Guy'),
  (6134, 845, 'But I think I''ll go to the dining car.', 'Guy'),
  (6135, 845, 'You mean before or after I kill him?', 'Bruno'),
  (6136, 845, 'Let''s change subject, Bruno, can''t we?', 'Guy'),
  (6137, 845, 'I used to put myself to sleep at night -- figuring it out.', 'Bruno'),
  (6138, 845, 'Like you do my murder and I do yours.', 'Bruno'),
  (6139, 845, 'You''re the one who''s in a hurry, aren''t you?', 'Guy'),
  (6140, 845, 'I didn''t want this divorce, you did.', 'Guy'),
  (6141, 845, 'You black conniving little liar!', 'Guy'),
  (6142, 845, 'I''d like to break her neck!', 'Guy'),
  (6143, 845, 'I''m sick and tired of bowing and scraping to the king.', 'Bruno'),
  (6144, 845, 'So she double-crossed you!', 'Bruno'),
  (6145, 845, 'You''ll never make the Metropolitan.', 'Guy'),
  (6146, 845, 'Are you trying to tell me you''ve -- Why, you maniac!', 'Guy'),
  (6147, 845, 'Tell them you know about it already, Guy.', 'Bruno'),
  (6148, 845, 'Before we go into the living room.', 'Anne'),
  (6149, 845, 'Let''s not fool ourselves.', 'Barbara'),
  (6150, 845, 'It can''t be helped, darling.', 'Anne'),
  (6151, 845, 'You won''t forget that call, Guy?', 'Senator'),
  (6152, 845, 'Unfortunately, I remember very little about the journey from New York...You see, there had been a little celebration --', 'Collins'),
  (6153, 845, 'They sometimes throw a suspect in the can and keep him there all night.', 'Barbara'),
  (6154, 845, 'They gave me a present -- come take a look.', 'Guy'),
  (6155, 845, 'You''ve got to carry on as though nothing has happened.', 'Anne'),
  (6156, 845, 'I was beginning to feel like a goldfish.', 'Guy'),
  (6157, 845, 'Yes, if I can get a court at the club.', 'Guy'),
  (6158, 845, 'I''ve just been talking to your shadow.', 'Barbara'),
  (6159, 845, 'He sticks so close he''s beginning to grow on me -- like a fungus.', 'Guy'),
  (6160, 845, 'I''m already developing my faculty for seeing millions of miles.', 'Bruno'),
  (6161, 845, 'Antony, you seem very interested in the subject of murder.', 'Mrs. Cunningham'),
  (6162, 845, 'Bang, bang, all over the place.', 'Bruno'),
  (6163, 845, 'Cunningham''s chin at the top of the screen.', 'Closeup'),
  (6164, 845, 'What''s the matter, Barbara?', 'Anne'),
  (6165, 845, 'What did Miriam look like, Guy.', 'Anne'),
  (6166, 845, 'He suggested that if he got rid of Miriam for me, I should kill his father.', 'Guy'),
  (6167, 845, 'And now that you know, you''re acting guilty, too.', 'Guy'),
  (6168, 845, 'Since you sent me a key to your house, I decided to use it -- to make a little social call on your father.', 'Guy'),
  (6169, 845, 'I''m a very clever follow.', 'Bruno'),
  (6170, 845, 'I know Bruno''s been in some very awkward scrapes, but nothing so ridiculous as a murder.', 'Mrs. Antony'),
  (6171, 845, 'He shouldn''t have sent you on an errand like this.', 'Bruno'),
  (6172, 845, 'Now, I really must go...if you''ll excuse me...', 'Bruno'),
  (6173, 845, 'This is the first time I ever waited for a murder suspect to play tennis before I pulled him in.', 'Hammond'),
  (6174, 845, 'Then he''ll think of something.', 'Guy'),
  (6175, 845, 'Hammond rolls his eyes in disgust at Hennessy''s politeness.', 'Hennessy'),
  (6176, 845, 'You don''t have to understand, just do it.', 'Anne'),
  (6177, 845, 'Don''t just stand here -- do something!', 'Bruno'),
  (6178, 845, 'Guy says you love steak -- rare, Medium, or well-done?', 'Barbara'),
  (6179, 845, 'For a moment we don''t know who has survived.', 'Long Shot From High Angle'),
  (6180, 845, 'No, they''ve done everything they can until the crane comes.', 'Policeman'),
  (6431, 871, 'So ends my last signal until we reach our destination.', 'Astronaut''S Voice'),
  (6432, 871, 'He begins to feel like no more than a mote in the eye of eternity.', 'Taylor'),
  (6433, 871, 'We weren''t programmed to land in water.', 'Landon'),
  (6434, 871, 'She''s been dead nearly a year.', 'Taylor'),
  (6435, 871, 'There''s a mantle of dust around this planet and yet it''s as humid as a jungle.', 'Dodge'),
  (6436, 871, 'Straighten me out on something.', 'Taylor'),
  (6437, 871, 'You got what you wanted, kid.', 'Taylor'),
  (6438, 871, 'It''s loaded with minerals, but safe.', 'Dodge'),
  (6439, 871, 'Which one was wearing the strange clothes?', 'Zira'),
  (6440, 871, 'I''m an animal psychologist, that''s all.', 'Zira'),
  (6441, 871, 'Well, Bright Eyes, is our throat feeling better?', 'Zira'),
  (6442, 871, 'A man who acts like an ape.', 'Zaius'),
  (6443, 871, 'Besides, men are a nuisance.', 'Zaius'),
  (6444, 871, 'The project will require my support, of course.', 'Zaius'' Voice'),
  (6445, 871, 'Besides, it''s against the rules.', 'Julius'),
  (6446, 871, 'And even if it weren''t, why fly?', 'Zira'),
  (6447, 871, '-- that the ape evolved from a lower order of primate, possibly man.', 'Zira'),
  (6448, 871, 'I was just assembling my notes.', 'Cornelius'),
  (6449, 871, 'She wants this pair to mate.', 'Julius'' Voice'),
  (6450, 871, 'I''m in charge of this man.', 'Zira'),
  (6451, 871, 'What are you going to do?', 'Taylor'),
  (6452, 871, 'It''s probably just as well she didn''t live to see this.', 'Taylor'),
  (6453, 871, 'And our purpose is to settle custodial and jurisdictional questions concerning this beast, and determine what''s to be done with him.', 'Maximus'),
  (6454, 871, 'It says here that his name is Bright Eyes.', 'President'),
  (6455, 871, 'Mind your tongue, madame.', 'President'),
  (6456, 871, 'Show this to the President.', 'Taylor'),
  (6457, 871, 'My witnesses -- correction -- my exhibits are on display in the amphitheater.', 'Honorius'),
  (6458, 871, 'But this much is certain -- he comes from somewhere in the Forbidden Zone.', 'Cornelius'),
  (6459, 871, 'As an animal psychologist, I have found no physiological defect to explain why humans are mute.', 'Zira'),
  (6460, 871, 'Oh, your case was preordained.', 'Zaius'),
  (6461, 871, 'Then how is it we speak the same language?', 'Zaius'),
  (6462, 871, 'Thank you for calling me Taylor.', 'Taylor'),
  (6463, 871, 'All right, you can cut me to pieces.', 'Taylor'),
  (6464, 871, 'This abduction was her idea.', 'Lucius'),
  (6465, 871, 'I''ll have to ask you to take them along.', 'Leader'),
  (6466, 871, 'Zaius seems to think there might be another jungle beyond the Forbidden Zone.', 'Taylor'),
  (6467, 871, 'There is no fresh water, no vegetation.', 'Cornelius'),
  (6468, 871, 'Something''s wrong with your mate.', 'Lucius'),
  (6469, 871, 'It makes you look somehow ...', 'Cornelius'),
  (6470, 871, 'On this planet -- it''s easy.', 'Taylor'),
  (6471, 871, 'Maybe I can pay you back.', 'Taylor'),
  (6472, 871, 'Don''t speak to me in absolutes.', 'Zaius'),
  (6473, 871, 'Have you forgotten your Scripture?', 'Zaius'),
  (6474, 871, 'I don''t say he was a man like an Earthman, but I''d call him a close relative, for he was plagued by most of man''s ills.', 'Taylor'),
  (6475, 871, 'I want you to go around the bend and tell those gorillas their leader is my prisoner.', 'Taylor'),
  (6476, 871, 'You owe him your science, your language, whatever knowledge you have.', 'Taylor'),
  (6477, 871, 'Let him not breed in great numbers, for he will make a desert of his home and yours.', 'Cornelius'),
  (6478, 871, 'Would you like to come along?', 'Taylor'),
  (6479, 871, 'All my life I''ve awaited your coming and dreaded it.', 'Zaius'),
  (6480, 871, 'A world turned wrong side up.', 'Taylor');
INSERT INTO quotes (id, movie_id, text, character) VALUES
  (8981, 3114, 'That old goat still creakin'' around?...', 'Ethan'),
  (8982, 3114, 'But I''ve got to help with the dishes.', 'Debbie'),
  (8983, 3114, 'Passed the Todd place comin'' in...', 'Ethan'),
  (8984, 3114, 'You mean those pure breds he just bought?', 'Aaron'),
  (8985, 3114, 'I still got my sabre, Reverend...', 'Ethan'),
  (8986, 3114, 'I took mine to the Confederate States of America...', 'Ethan'),
  (8987, 3114, 'Ain''t but one tribe uses a lance like that!', 'Ethan'),
  (8988, 3114, 'We don''t need the lamp yet...', 'Martha'),
  (8989, 3114, '...and to Your keeping we commend the souls of Aaron...', 'Clayton'),
  (8990, 3114, 'This ''un come a long way ''fore he died.', 'Charlie'),
  (8991, 3114, 'Soon''s it gets dark we''ll circle out so''s to jump ''em before daybreak.', 'Ethan'),
  (8992, 3114, 'But if you''re wrong, Captain Clayton, don''t ever give me another!', 'Ethan'),
  (8993, 3114, 'It makes them think their medicine''s stronger than yours...', 'Ethan'),
  (8994, 3114, 'Reckon we got to go back -- Ed''s shoulder is smashed -- bad!', 'Charlie'),
  (8995, 3114, 'a human man rides a horse till it dies...', 'Ethan'),
  (8996, 3114, 'What happened to your blanket?', 'Martin'),
  (8997, 3114, 'Let''s just hope he took some with him...', 'Ethan'),
  (8998, 3114, 'And him probably forgettin'' all about you!...', 'Mrs. Jorgensen'),
  (8999, 3114, 'Trouble is we don''t even know which band that war party belonged to...', 'Ethan'),
  (9000, 3114, 'Would it be all right if we gave him some of Brad''s things?', 'Laurie'),
  (9001, 3114, 'She''s no kin to you at all!', 'Ethan'),
  (9002, 3114, 'Laurie, I''ve seen his eyes when he so much as hears the word ''Comanche'' ...I''ve seen him take his knife an'' ...never mind...', 'Martin'),
  (9003, 3114, 'but don''t count on finding me here when you get back...', 'Laurie'),
  (9004, 3114, 'Scar''s band was headin'' north...', 'Futterman'),
  (9005, 3114, 'Sorta like ''roundabout'' -- like a man says he''s goin'' one place when he means to go just the reverse...', 'Ethan'),
  (9006, 3114, 'After all, Charlie brought the letter, Laurie...', 'Jorgensen'),
  (9007, 3114, 'figgerin'' that''d make it easier for us to come an'' go...', 'Martin''S Voice'),
  (9008, 3114, 'Look, I changed my mind...', 'Martin'),
  (9009, 3114, 'I don''t think it''s so funny...', 'Martin'),
  (9010, 3114, 'We were heading north, through the buffalo country when something happened that I ain''t got straight in my own mind yet...', 'Laurie'),
  (9011, 3114, 'Just hope we ain''t too late...', 'Ethan'),
  (9012, 3114, 'You''ll have to wait until we reach the agency...', 'Officer'),
  (9013, 3114, 'Unfortunately, the hostiles murdered them as we developed the village...', 'General'),
  (9014, 3114, 'They''re not white any more -- they''re Comanche!...', 'Ethan'),
  (9015, 3114, 'And you knittin'' that muffler...', 'Mrs. Jorgensen'),
  (9016, 3114, 'You look mangier ''n ever.', 'Ethan'),
  (9017, 3114, 'Take yer hands off''n me...', 'Martin'),
  (9018, 3114, 'So his wives sit on the honor side of his lodge.', 'Emilio''S Voice'),
  (9019, 3114, 'I do not want blood money.', 'Emilio'),
  (9020, 3114, 'Remember how I used to let you ride my horse?', 'Martin'),
  (9021, 3114, 'Say, that music sounds so good it must be sinful...', 'Clayton'),
  (9022, 3114, 'She''s not a little girl any more.', 'Ethan'),
  (9023, 3114, 'I''ll thank you to leave the room, Laurie.', 'Charlie'),
  (9024, 3114, 'Well, go get cleaned up and we''ll proceed with the weddin''...', 'Clayton'),
  (9025, 3114, 'Is Captain Clayton here, Reverend?', 'Lieutenant'),
  (9026, 3114, 'He talks crazy but I brought him along...', 'Lieutenant'),
  (9027, 3114, 'Sonny, yonder''s a passel of murderers, complete with Texican scalps an'' white girl captive...', 'Clayton'),
  (9028, 3114, 'It''s what I''m countin'' on.', 'Ethan'),
  (9029, 3114, 'an'' try to get her out before you come chargin'' in.', 'Martin'),
  (9030, 3114, 'I don''t aim to raise no two hollers on any subject at hand...', 'Clayton'),
  (9031, 3116, 'Tonight we''ll discuss a subject most of us seem to consider either bad taste or frivolous or funny.', 'Moderator'),
  (9032, 3116, 'Just keep your pants on, ladies...', 'Job'),
  (9033, 3116, 'You ain''t coming to work?', 'Ralph'),
  (9034, 3116, 'Benson and Hedges One Hundreds makes special awards from time to time for anything that''s longer than anything...', 'Announcer''S Voice'),
  (9035, 3116, 'I ain''t shined my own shoes or shaved my own face in forty years, how''s that?', 'Salesman'),
  (9036, 3116, 'I''m bound for New York City.', 'Joe'),
  (9037, 3116, 'Three of us made a deal for, twenty-five, see, big goddam bargain?', 'Veteran'),
  (9038, 3116, 'Expect me when you see me.', 'Sally Buck'),
  (9039, 3116, 'You''re not looking for the Statue of Liberty at all.', 'Rich Lady'),
  (9040, 3116, 'Now lookie, when do you want me to meet you?', 'Cass'),
  (9041, 3116, 'Said, a person''s gotta make a living.', 'Cass'),
  (9042, 3116, 'I am a gorgeous chick, thirty-one, that''s right, you said it!', 'Cass'),
  (9043, 3116, 'Kee-rist, you really know the ropes.', 'Joe'),
  (9044, 3116, 'Operates the biggest stable in town.', 'Ratso'),
  (9045, 3116, 'But I''m sure he has that all figured out...', 'Jackie'),
  (9046, 3116, 'What''m I dragging my bum leg all over town for?', 'Ratso'),
  (9047, 3116, 'The point is he needs you.', 'Ratso'),
  (9048, 3116, 'No sir, I''m no cowboy really, but I''m a first class stud.', 'Joe'),
  (9049, 3116, 'Dammit, you take it and go about your business, that''s all.', 'O''Daniel'),
  (9050, 3116, 'That''s the ticket, just open your heart and let it flow.', 'O''Daniel'),
  (9051, 3116, 'Listen, tell you what, you can keep all the rest of the goddam junk if you let me have just the suitcase.', 'Joe'),
  (9052, 3116, 'What''re you going to do to me?', 'Fat Boy'),
  (9053, 3116, 'After this message from...', 'Bonner'),
  (9054, 3116, 'I got better things to do than talk to you.', 'Joe'),
  (9055, 3116, 'Comfortable, kee-rist, I slept on subways softer than this.', 'Joe'),
  (9056, 3116, 'Well, I hope you know what you''re in for.', 'Joe'),
  (9057, 3116, 'And keep your meat hooks off my radio.', 'Joe'),
  (9058, 3116, 'They lie out in their pagodas and pergolas waiting to grab the first jockstrap that passes.', 'Ratso'),
  (9059, 3116, 'Make that twenty-three bucks.', 'Joe''S Voice'),
  (9060, 3116, 'And end up a hunchback like my old man?', 'Ratso'),
  (9061, 3116, 'Okay, you got yourself one handsome, sweet-smelling cowboy, strut your stuff...', 'Joe'),
  (9062, 3116, 'You just let some poor bastard freeze to death, wouldn''t you?', 'Joe'),
  (9063, 3116, 'You even steal flowers for his grave.', 'Joe'),
  (9064, 3116, 'why can''t you be like your brothers?', 'Ratso'),
  (9065, 3116, 'It don''t say nothing about you...', 'Joe'),
  (9066, 3116, 'I mean there''s beer and so forth.', 'Hansel'),
  (9067, 3116, 'And I happen to be his manager.', 'Ratso'),
  (9068, 3116, 'And for that service I charge one dollar taxi fare.', 'Ratso'),
  (9069, 3116, 'Maybe we should take a little nap, see what happens?', 'Shirley'),
  (9070, 3116, 'Just one bitsy Y word and I gonna beat you!', 'Joe'),
  (9071, 3116, 'Well, ma''am -- Shirley -- I sure hate to trouble you, but...', 'Joe''S Voice'),
  (9072, 3116, 'So you gonna get you the best goddam doctor in this town and get yourself straightened out, that''s what.', 'Joe'),
  (9073, 3116, 'I don''t even want you to go.', 'Ratso'),
  (9074, 3116, 'Besides, you look very elegant...', 'Towny'),
  (9075, 3116, 'I''m through talking for the evening.', 'Towny'),
  (9076, 3116, 'I was so childish with her.', 'Towny'),
  (9077, 3116, 'I simply don''t have it, Joe.', 'Towny'),
  (9078, 3116, 'You get your first palm tree in South Carolina.', 'Ratso'),
  (9079, 3116, 'Hell, don''t cry about it!', 'Joe'),
  (9080, 3116, 'I ain''t even any goddam good as a bum.', 'Joe'),
  (9431, 4808, 'Don''t tell me you didn''t know it was loaded.', 'Reggie'),
  (9432, 4808, 'I''m afraid I already know a great many people.', 'Reggie'),
  (9433, 4808, 'Is your husband with you?', 'Peter'),
  (9434, 4808, 'I''ll get you some here, okay?', 'Reggie'),
  (9435, 4808, 'There was no other baggage.', 'Grandpierre'),
  (9436, 4808, 'I wanted to tell you how sorry I am -- and to find out if there was anything I could do.', 'Peter'),
  (9437, 4808, 'It''s not exactly what I''d call a large turn-out.', 'Reggie'),
  (9438, 4808, 'Excuse me for a moment, Mrs.', 'Bartholomew'),
  (9439, 4808, 'What''s all this got to do with me, Mr.', 'Reggie'),
  (9440, 4808, 'You''re Charles Voss''s wife -- now that he''s dead you''re their only lead.', 'Bartholomew'),
  (9441, 4808, 'You may not have a great deal of time.', 'Bartholomew'),
  (9442, 4808, 'The man and the woman are married --', 'Reggie'),
  (9443, 4808, 'Lampert -- you do know that, don''t you?', 'Gideon'),
  (9444, 4808, 'You''re insane, absolutely insane!', 'Reggie'),
  (9445, 4808, 'Look, I know it''s asking you to stretch your imagination, but can''t you pretend for a moment that I''m a woman and that you''re a --', 'Reggie'),
  (9446, 4808, 'Lock the door and the window -- and don''t let anyone in except me.', 'Peter'),
  (9447, 4808, 'We appreciate it, really we do.', 'Gideon'),
  (9448, 4808, 'No, it isn''t -- where''s the money?', 'Peter'),
  (9449, 4808, 'What''s wrong -- is he still there?', 'Scobie'),
  (9450, 4808, 'You mean he might have -- Mr.', 'Reggie'),
  (9451, 4808, 'Gratin�e, choucroute garnie, salade de pommes -- et un ballon de rouge.', 'Reggie'),
  (9452, 4808, 'Carson was dying so they were forced to leave him.', 'Bartholomew'),
  (9453, 4808, 'What do you want me to do?', 'Reggie'),
  (9454, 4808, 'But you know my name -- it''s Dyle.', 'Dyle'),
  (9455, 4808, 'She has it -- you know that.', 'Dyle'),
  (9456, 4808, 'Would you like to see where I was tattooed?', 'Dyle'),
  (9457, 4808, 'So was Juliet -- at fifteen.', 'Dyle'),
  (9458, 4808, 'They wouldn''t do anything to a little boy, would they?', 'Reggie'),
  (9459, 4808, 'Up till now we always figured she had the money -- but you know so much about it, maybe you''ve got it.', 'Gideon'),
  (9460, 4808, 'Mebbe we''d better call Herman.', 'Tex'),
  (9461, 4808, 'Jumpin'' frejoles -- it''s Herman''s spare.', 'Tex''S Voice'),
  (9462, 4808, 'It is only a guess, of course -- I hope none of you ever finds out for certain.', 'Grandpierre'),
  (9463, 4808, 'Would you do anything like that?', 'Reggie'),
  (9464, 4808, 'How often do you go through this little ritual?', 'Reggie'),
  (9465, 4808, 'Nothing''s going to happen to you while I''m around -- I want you to believe that.', 'Dyle'),
  (9466, 4808, 'But that left me without any honest means of support.', 'Dyle'),
  (9467, 4808, 'There aren''t many men who love their work as much as I do.', 'Adam'),
  (9468, 4808, 'Aren''t you allowed to kiss back?', 'Reggie'),
  (9469, 4808, 'Now Dyle, you listen to me -- my mama didn''t raise no stupid children.', 'Tex'),
  (9470, 4808, 'I''ll bet you don''t really need those.', 'Reggie'),
  (9471, 4808, 'Reggie -- I think I''ve found -- are you on?', 'Adam'),
  (9472, 4808, 'Well -- it was a place -- a street corner, I think.', 'Reggie'),
  (9473, 4808, 'He''s already killed three men.', 'Reggie'),
  (9474, 4808, 'Those stamps -- they''re worth a fortune!', 'Reggie'),
  (9475, 4808, 'Lampert -- you''d better give that to me slowly.', 'Bartholomew'),
  (9476, 4808, 'This car is for first class only -- you have a second-class ticket.', 'Train Guard'),
  (9477, 4808, 'Bartholomew -- he''s chasing me!', 'Reggie'),
  (9478, 4808, 'I know you''re in there, Mrs.', 'Carson''S Voice'),
  (9479, 4808, 'You might try the Treasury Department, ma''am -- Room 216, second floor, Mr.', 'Marine'),
  (9480, 4808, 'Okay, now -- hand over those stamps.', 'Cruikshank'),
  (13336, 37247, 'Were there NOT a purpose, then all of these past years of struggle, of fierce competition and of uncom- promising ambition would be mean- ingless.', 'Ben'),
  (13337, 37247, 'The guests are all downstairs, Ben.', 'Mr. Braddock''S Voice'),
  (13338, 37247, 'Excuse me - I think I''d just like to check something on the car for a minute -', 'Ben'),
  (13339, 37247, 'The bathroom is down at the end of the hall.', 'Ben'),
  (13340, 37247, 'But I have some things on my mind.', 'Ben'),
  (13341, 37247, 'My husband will be back quite late.', 'Mrs. Robinson'),
  (13342, 37247, 'We had it done last Christmas.', 'Mrs. Robinson'),
  (13343, 37247, 'Haven''t you ever seen anybody in a slip before?', 'Mrs. Robinson'),
  (13344, 37247, 'I apologize for what I said.', 'Ben'),
  (13345, 37247, 'Will you bring it in to me?', 'Mrs. Robinson''S Voice'),
  (13346, 37247, 'No - I''m just - I''m just a little worried about my future.', 'Ben'),
  (13347, 37247, 'I''ve watched you grow up, Ben.', 'Mr. Robinson'),
  (13348, 37247, 'Ben - I want you to give her a call.', 'Mr. Robinson'),
  (13349, 37247, 'I''d like to discuss this.', 'Ben''S Voice'),
  (13350, 37247, 'You must be one of the Porters.', 'Mrs. Singleman'),
  (13351, 37247, 'Do you want to get it now?', 'Mrs. Robinson'),
  (13352, 37247, 'I mean - I don''t know what their policy is - but -', 'Ben'),
  (13353, 37247, 'Robinson - I can''t do this.', 'Ben'),
  (13354, 37247, 'Well - I would say that I''m just drifting.', 'Ben''S Voice'),
  (13355, 37247, 'Well I''m going to ask you what you do when you go off at night.', 'Mrs. Braddock'),
  (13356, 37247, 'I usually get kind of drunk.', 'Ben'),
  (13357, 37247, 'Well what do you want to talk about?', 'Mrs. Robinson'),
  (13358, 37247, 'Do you really want me to?', 'Mrs. Robinson'),
  (13359, 37247, 'Because he takes sleeping pills.', 'Mrs. Robinson'),
  (13360, 37247, 'Man, is this interesting.', 'Ben'),
  (13361, 37247, 'Was he a law student at the time?', 'Ben'),
  (13362, 37247, 'Benjamin, don''t you ever take that girl out.', 'Mrs. Robinson'),
  (13363, 37247, 'I am not proud that I spend my time with a broken- down alcoholic!', 'Ben'),
  (13364, 37247, 'Well it''s pretty obvious you don''t want me around any more.', 'Mrs. Robinson'),
  (13365, 37247, 'It never occured to me to take her out.', 'Ben'),
  (13366, 37247, 'I guess your evenings, whatever you do with them, are just too valuable.', 'Mr. Braddock'),
  (13367, 37247, 'Well - I want you to keep your wits about you tonight.', 'Mr. Robinson''S Voice'),
  (13368, 37247, 'But could I just tell you this one thing?', 'Ben'),
  (13369, 37247, 'No - I was just thinking - look - it''s still early - we could do something - go somewhere else.', 'Ben'),
  (13370, 37247, 'Benjamin - are having an affair with someone?', 'Elaine'),
  (13371, 37247, 'Then you''d better start believing me.', 'Mrs. Robinson'),
  (13372, 37247, 'Oh, Ben - this is so - exciting -', 'Mrs. Braddock'),
  (13373, 37247, 'To be perfectly honest, she doesn''t like me.', 'Ben'),
  (13374, 37247, 'Shall I call her for you?', 'Lady Receptionist No. 1'),
  (13375, 37247, 'I thought he said by the monkey house.', 'Elaine'),
  (13376, 37247, 'Well, I want you to leave.', 'Elaine'),
  (13377, 37247, 'Benjamin - this is my mother!', 'Elaine'),
  (13378, 37247, 'Well - where are you going?', 'Elaine'),
  (13379, 37247, 'I just don''t think it would work.', 'Elaine'),
  (13380, 37247, 'He said he thought we''d make a pretty good team.', 'Elaine'),
  (13381, 37247, 'I am not threatening you.', 'Ben'),
  (13382, 37247, 'We might - we might just as well have been shaking hands.', 'Ben'),
  (13383, 37247, 'McCleery - do you have some change?', 'Ben'),
  (13384, 37247, 'I''m sorry we won''t be able to invite you to the wedding, Benjamin, but the arrangements have been so rushed -', 'Mrs. Robinson'),
  (13385, 37247, 'You don''t happen to know exactly where the Make Out King is getting married, do you?', 'Ben');
